<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">stderr</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">Stdio</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">piped</span><span style="color:#9399B2;">())</span></span>
